  ('medical-tech-moex-17818', 'medical-tech', 'medical-tech-moex-096-05118730', 'sub-medical-tech-09', NULL, 'single_choice', '下列有關Legionella pneumophila特性之敘述，何者正確？', '["沒有運動性，可在水中自由營生", "可以醱酵葡萄糖產酸", "屬革蘭氏陰性桿菌，細胞壁含有特殊支鏈脂肪酸", "主要經飛沫在人與人之間互相傳染，引起Q熱"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:08+00:00", "source_pdf_sha1": "c1b8543e6e72", "answer_pdf_sha1": "0579d7726f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學（包括細菌與黴菌）", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 59, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-17819', 'medical-tech', 'medical-tech-moex-096-05118730', 'sub-medical-tech-09', NULL, 'single_choice', '下列有關Helicobacter pylori之敘述，何者正確？', '["革蘭氏變異性彎曲桿菌，沒有運動性", "兼性厭氧菌（Facultative anaerobe）", "強尿素酶活性使其能在胃黏膜中存活，並與致病力有關", "可利用含cephalothin之Campy-BAP從病人胃黏膜檢體分離"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:08+00:00", "source_pdf_sha1": "c1b8543e6e72", "answer_pdf_sha1": "0579d7726f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學（包括細菌與黴菌）", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 60, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-17820', 'medical-tech', 'medical-tech-moex-096-05118730', 'sub-medical-tech-09', NULL, 'single_choice', '下列有關分離Campylobacter jejuni及Campylobacter coli等腸道病原菌之敘述，何項錯誤？', '["糞便不能立刻送檢時，宜使用Cary-Blair transport medium", "宜使用選擇性培養基，在42℃高濕度環境培養", "宜使用TCBS agar，培養在一般大氣培養箱", "0.65 µm濾膜過濾法（filtration method）可提高分離率"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:08+00:00", "source_pdf_sha1": "c1b8543e6e72", "answer_pdf_sha1": "0579d7726f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學（包括細菌與黴菌）", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 61, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-17821', 'medical-tech', 'medical-tech-moex-096-05118730', 'sub-medical-tech-09', NULL, 'single_choice', '腹瀉病原菌Plesiomonas shigelloides可能與D群志賀氏菌（Shigella）抗血清產生交叉反應，因而導 致錯誤鑑定，下列何種試驗有助於鑑別？', '["HS", "Glucose fermentation", "Catalase", "Oxidase 2"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:08+00:00", "source_pdf_sha1": "c1b8543e6e72", "answer_pdf_sha1": "0579d7726f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學（包括細菌與黴菌）", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 62, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-17822', 'medical-tech', 'medical-tech-moex-096-05118730', 'sub-medical-tech-09', NULL, 'single_choice', '下列有關Aeromonas hydrophila之敘述，何者錯誤？', '["主要感染源是水，可引起人類腸胃炎、敗血症、傷口感染等", "具周鞭毛，不具溶血性", "Glucose fermentation", "Oxidase陽性"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:08+00:00", "source_pdf_sha1": "c1b8543e6e72", "answer_pdf_sha1": "0579d7726f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學（包括細菌與黴菌）", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 63, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-17823', 'medical-tech', 'medical-tech-moex-096-05118730', 'sub-medical-tech-09', NULL, 'single_choice', '臨床上分離霍亂弧菌時，下列何者不能用來區分其classic及El Tor兩種生物型？', '["Modified CAMP test", "Voges-Proskauer（VP）test", "雞紅血球凝集試驗（chicken RBC agglutination）", "弦線試驗（string test）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:08+00:00", "source_pdf_sha1": "c1b8543e6e72", "answer_pdf_sha1": "0579d7726f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學（包括細菌與黴菌）", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 64, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-17824', 'medical-tech', 'medical-tech-moex-096-05118730', 'sub-medical-tech-09', NULL, 'single_choice', '若病人嚴重水瀉，排出的糞便呈米湯樣（rice water），則宜接種於下列何種培養基，以利病原菌 的分離？', '["TCBS（Thiosulfate citrate bile salts sucrose agar）", "Campy-BAP", "Egg yolk agar", "BCYEα agar"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:08+00:00", "source_pdf_sha1": "c1b8543e6e72", "answer_pdf_sha1": "0579d7726f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學（包括細菌與黴菌）", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 65, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-17825', 'medical-tech', 'medical-tech-moex-096-05118730', 'sub-medical-tech-09', NULL, 'single_choice', '下述有關Stenotrophomonas maltophilia之特性，何者正確？', '["對麥芽糖（maltose）的氧化作用比葡萄糖還強", "Oxidase(+)，具單一鞭毛", "對大部分β-lactam類藥物具感受性", "Lysine decarboxylase，DNase及gelatinase均為陰性"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:08+00:00", "source_pdf_sha1": "c1b8543e6e72", "answer_pdf_sha1": "0579d7726f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學（包括細菌與黴菌）", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 66, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-17826', 'medical-tech', 'medical-tech-moex-096-05118730', 'sub-medical-tech-09', NULL, 'single_choice', '臨床上可依據一些生理特性快速鑑定綠膿桿菌（Pseudomonas aeruginosa），下列何者不是其特性？', '["BAP上β-溶血之扁平大型菌落，表面有金屬光澤", "菌落有葡萄芳香味及擴散性藍綠色色素", "不能在MacConkey agar上生長", "Oxidase(+)，有運動性"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:08+00:00", "source_pdf_sha1": "c1b8543e6e72", "answer_pdf_sha1": "0579d7726f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學（包括細菌與黴菌）", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 67, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-17827', 'medical-tech', 'medical-tech-moex-096-05118730', 'sub-medical-tech-09', NULL, 'single_choice', '下列有關Acinetobacter baumannii特性之敍述，何者正確？', '["Oxidase及catalase均為陽性", "具周鞭毛，有運動性", "不易產生抗藥性，對penicillin敏感", "革蘭氏陰性，球狀或球桿狀，可氧化10%乳糖，且能在42℃生長"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:08+00:00", "source_pdf_sha1": "c1b8543e6e72", "answer_pdf_sha1": "0579d7726f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學（包括細菌與黴菌）", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 68, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL)
